24	pub(crate) type ParserInput<'a> = LocatedSpan<&'a [u8], &'a str>;
25	// Change this to something else that implements ParseError to get a
26	// different error type out of nom.
27	pub(crate) type NomError<'a> = nom::error::Error<ParserInput<'a>>;
28	
29	pub(crate) type NomResult<'a, O, E = NomError<'a>> = IResult<ParserInput<'a>, O, E>;
30	
31	#[inline]
32	fn strip_nom<O>(r: NomResult<O>) -> Option<O> {
33	    r.ok().map(|(_, o)| o)
34	}
35	
36	#[inline]
37	fn convert_result<O, E>(result: Result<O, E>, input: ParserInput, error_kind: ErrorKind) -> NomResult<O> {
38	    result.map(|o| (input, o)).map_err(|_| {
39	        // this is a unit bind if NomError = ()
40	        let err: NomError = nom::error::Error::from_error_kind(input, error_kind);
41	        nom::Err::Error(err)
42	    })
43	}
