95	fn integer(input: ParserInput) -> NomResult<i64> {
96	    let (i, _) = pair(opt(one_of("+-")), digit1).parse(input)?;
97	
98	    let int_input = &input[..input.len() - i.len()];
99	    convert_result(i64::from_str(str::from_utf8(int_input).unwrap()), i, ErrorKind::Digit)
100	}
101	
102	fn real(input: ParserInput) -> NomResult<f32> {
103	    let (i, _) = pair(
104	        opt(one_of("+-")),
105	        alt((
106	            map((digit1, tag(&b"."[..]), digit0), |_| ()),
107	            map(pair(tag(&b"."[..]), digit1), |_| ()),
108	        )),
109	    ).parse(input)?;
110	
111	    let float_input = &input[..input.len() - i.len()];
112	    convert_result(f32::from_str(str::from_utf8(float_input).unwrap()), i, ErrorKind::Digit)
113	}
