115	pub(crate) fn hex_char(input: ParserInput) -> NomResult<u8> {
116	    map_res(
117	        verify(take(2usize), |h: &ParserInput| {
118	            h.as_bytes().iter().copied().all(AsChar::is_hex_digit)
119	        }),
120	        |x: ParserInput| u8::from_str_radix(str::from_utf8(&x).unwrap(), 16),
121	    ).parse(input)
122	}
123	
124	fn oct_char(input: ParserInput) -> NomResult<u8> {
125	    map_res(
126	        take_while_m_n(1, 3, AsChar::is_oct_digit),
127	        // Spec requires us to ignore any overflow.
128	        |x: ParserInput| u16::from_str_radix(str::from_utf8(&x).unwrap(), 8).map(|o| o as u8),
129	    ).parse(input)
130	}
131	
132	pub(crate) fn name(input: ParserInput) -> NomResult<Vec<u8>> {
133	    preceded(
134	        tag(&b"/"[..]),
135	        many0(alt((
136	            preceded(tag(&b"#"[..]), hex_char),
137	            map_opt(take(1usize), |c: ParserInput| {
138	                if c[0] != b'#' && is_regular(c[0]) {
139	                    Some(c[0])
140	                } else {
141	                    None
142	                }
143	            }),
144	        ))),
145	    ).parse(input)
146	}
147	
148	fn escape_sequence(input: ParserInput) -> NomResult<Option<u8>> {
149	    preceded(
150	        tag(&b"\\"[..]),
151	        alt((
152	            map(oct_char, Some),
153	            map(eol, |_| None),
154	            map(tag(&b"n"[..]), |_| Some(b'\n')),
155	            map(tag(&b"r"[..]), |_| Some(b'\r')),
156	            map(tag(&b"t"[..]), |_| Some(b'\t')),
157	            map(tag(&b"b"[..]), |_| Some(b'\x08')),
158	            map(tag(&b"f"[..]), |_| Some(b'\x0C')),
159	            map(take(1usize), |c: ParserInput| Some(c[0])),
160	        )),
161	    ).parse(input)
162	}
