164	enum InnerLiteralString<'a> {
165	    Direct(ParserInput<'a>),
166	    Escape(Option<u8>),
167	    Eol(ParserInput<'a>),
168	    Nested(Vec<u8>),
169	}
170	
171	impl InnerLiteralString<'_> {
172	    fn push(&self, output: &mut Vec<u8>) {
173	        match self {
174	            InnerLiteralString::Direct(s) | InnerLiteralString::Eol(s) => output.extend_from_slice(s),
175	            InnerLiteralString::Escape(e) => output.extend(e),
176	            InnerLiteralString::Nested(n) => output.extend_from_slice(n),
177	        }
178	    }
179	}
180	
181	fn inner_literal_string(depth: usize) -> impl Fn(ParserInput) -> NomResult<Vec<u8>> {
182	    move |input| {
183	        fold_many0(
184	            alt((
185	                map(take_while1(is_direct_literal_string), InnerLiteralString::Direct),
186	                map(escape_sequence, InnerLiteralString::Escape),
187	                map(eol, InnerLiteralString::Eol),
188	                map(nested_literal_string(depth), InnerLiteralString::Nested),
189	            )),
190	            Vec::new,
191	            |mut out: Vec<u8>, value| {
192	                value.push(&mut out);
193	                out
194	            },
195	        ).parse(input)
196	    }
197	}
198	
199	fn nested_literal_string(depth: usize) -> impl Fn(ParserInput) -> NomResult<Vec<u8>> {
200	    move |input| {
201	        if depth == 0 {
202	            map(verify(tag(&b"too deep"[..]), |_| false), |_| vec![]).parse(input)
203	        } else {
204	            map(
205	                delimited(tag(&b"("[..]), inner_literal_string(depth - 1), tag(&b")"[..])),
206	                |mut content| {
207	                    content.insert(0, b'(');
208	                    content.push(b')');
209	                    content
210	                },
211	            ).parse(input)
212	        }
213	    }
214	}
215	
216	fn literal_string(input: ParserInput) -> NomResult<Vec<u8>> {
217	    delimited(tag(&b"("[..]), inner_literal_string(crate::reader::MAX_BRACKET), tag(&b")"[..])).parse(input)
218	}
