220	#[inline]
221	fn hex_digit(input: ParserInput) -> NomResult<u8> {
222	    map_opt(take(1usize), |c: ParserInput| {
223	        str::from_utf8(&c).ok().and_then(|c| u8::from_str_radix(c, 16).ok())
224	    }).parse(input)
225	}
226	
227	fn hexadecimal_string(input: ParserInput) -> NomResult<Object> {
228	    map(
229	        delimited(
230	            tag(&b"<"[..]),
231	            terminated(
232	                fold_many0(
233	                    preceded(white_space, hex_digit),
234	                    || -> (Vec<u8>, bool) { (Vec::new(), false) },
235	                    |state, c| match state {
236	                        (mut out, false) => {
237	                            out.push(c << 4);
238	                            (out, true)
239	                        }
240	                        (mut out, true) => {
241	                            *out.last_mut().unwrap() |= c;
242	                            (out, false)
243	                        }
244	                    },
245	                ),
246	                white_space,
247	            ),
248	            tag(&b">"[..]),
249	        ),
250	        |(bytes, _)| Object::String(bytes, StringFormat::Hexadecimal),
251	    ).parse(input)
252	}
253	
254	fn boolean(input: ParserInput) -> NomResult<Object> {
255	    alt((
256	        map(tag(&b"true"[..]), |_| Object::Boolean(true)),
257	        map(tag(&b"false"[..]), |_| Object::Boolean(false)),
258	    )).parse(input)
259	}
260	
261	fn null(input: ParserInput) -> NomResult<Object> {
262	    map(tag(&b"null"[..]), |_| Object::Null).parse(input)
263	}
264	
265	fn array(input: ParserInput) -> NomResult<Vec<Object>> {
266	    delimited(pair(tag(&b"["[..]), space), many0(_direct_object), tag(&b"]"[..])).parse(input)
267	}
268	
269	pub(crate) fn dictionary(input: ParserInput) -> NomResult<Dictionary> {
270	    delimited(pair(tag(&b"<<"[..]), space), inner_dictionary, tag(&b">>"[..])).parse(input)
271	}
272	
273	fn inner_dictionary(input: ParserInput) -> NomResult<Dictionary> {
274	    fold_many0(
275	        pair(terminated(name, space), _direct_object),
276	        Dictionary::new,
277	        |mut dict, (key, value)| {
278	            dict.set(key, value);
279	            dict
280	        },
281	    ).parse(input)
282	}
283	
284	pub(crate) fn dict_dup(input: ParserInput) -> NomResult<Dictionary> {
285	    delimited(
286	        (
287	            digit1,
288	            space1,
289	            tag(&b"dict"[..]),
290	            space1,
291	            tag(&b"dup"[..]),
292	            space1,
293	            tag(&b"begin"[..]),
294	            multispace1,
295	        ),
296	        fold_many0(
297	            terminated(
298	                pair(terminated(name, space), _direct_object),
299	                pair(tag(&b"def"[..]), multispace1),
300	            ),
301	            Dictionary::new,
302	            |mut dict, (key, value)| {
303	                dict.set(key, value);
304	                dict
305	            },
306	        ),
307	        tag(&b"end"[..]),
308	    ).parse(input)
309	}
