311	fn stream<'a>(input: ParserInput<'a>, reader: &Reader, already_seen: &mut HashSet<ObjectId>) -> NomResult<'a, Object> {
312	    let (i, dict) = terminated(dictionary, (space, tag(&b"stream"[..]), space0, eol)).parse(input)?;
313	
314	    if let Ok(length) = dict.get(b"Length").and_then(|value| {
315	        if let Ok(id) = value.as_reference() {
316	            reader.get_object(id, already_seen).and_then(|value| value.as_i64())
317	        } else {
318	            value.as_i64()
319	        }
320	    }) {
321	        if length < 0 {
322	            // artificial error kind is created to allow descriptive nom errors
323	            return Err(nom::Err::Failure(NomError::from_error_kind(i, ErrorKind::LengthValue)));
324	        }
325	        let (i, data) = terminated(take(length as usize), pair(opt(eol), tag(&b"endstream"[..]))).parse(i)?;
326	        Ok((i, Object::Stream(Stream::new(dict, data.to_vec()))))
327	    } else {
328	        // Return position relative to the start of the stream dictionary.
329	        Ok((i, Object::Stream(Stream::with_position(dict, input.len() - i.len()))))
330	    }
331	}
