333	fn unsigned_int<I: FromStr>(input: ParserInput) -> NomResult<I> {
334	    map_res(digit1, |digits: ParserInput| {
335	        I::from_str(str::from_utf8(&digits).unwrap())
336	    }).parse(input)
337	}
