339	fn object_id(input: ParserInput) -> NomResult<ObjectId> {
340	    pair(terminated(unsigned_int, space), terminated(unsigned_int, space)).parse(input)
341	}
342	
343	fn reference(input: ParserInput) -> NomResult<Object> {
344	    map(terminated(object_id, tag(&b"R"[..])), Object::Reference).parse(input)
345	}
