347	fn _direct_objects(input: ParserInput) -> NomResult<Object> {
348	    alt((
349	        null,
350	        boolean,
351	        reference,
352	        map(real, Object::Real),
353	        map(integer, Object::Integer),
354	        map(name, Object::Name),
355	        map(literal_string, Object::string_literal),
356	        hexadecimal_string,
357	        map(array, Object::Array),
358	        map(dictionary, Object::Dictionary),
359	    )).parse(input)
360	}
361	
362	fn _direct_object(input: ParserInput) -> NomResult<Object> {
363	    terminated(_direct_objects, space).parse(input)
364	}
