366	pub fn direct_object(input: ParserInput) -> Option<Object> {
367	    strip_nom(_direct_object.parse(input))
368	}
369	
370	fn object<'a>(input: ParserInput<'a>, reader: &Reader, already_seen: &mut HashSet<ObjectId>) -> NomResult<'a, Object> {
371	    terminated(
372	        alt((|input| stream(input, reader, already_seen), _direct_objects)),
373	        space,
374	    ).parse(input)
375	}
