412	pub fn header(input: ParserInput) -> Option<String> {
413	    strip_nom(map_res(
414	        delimited(
415	            tag(&b"%PDF-"[..]),
416	            take_while(|c: u8| !b"\r\n".contains(&c)),
417	            pair(eol, many0_count(comment)),
418	        ),
