423	pub fn binary_mark(input: ParserInput) -> Option<Vec<u8>> {
424	    strip_nom(map_res(
425	        delimited(
426	            tag(&b"%"[..]),
427	            take_while(|c: u8| !b"\r\n".contains(&c)),
428	            pair(eol, many0_count(comment)),
