434	/// Decode CrossReferenceTable
435	fn xref(input: ParserInput) -> NomResult<Xref> {
436	    let xref_eol = map(alt((tag(&b" \r"[..]), tag(&b" \n"[..]), tag(&b"\r\n"[..]))), |_| ());
437	    let xref_entry = pair(
438	        separated_pair(unsigned_int, tag(&b" "[..]), unsigned_int::<u32>),
439	        delimited(tag(&b" "[..]), map(one_of("nf"), |k| k == 'n'), xref_eol),
440	    );
441	
442	    let xref_section = pair(
443	        separated_pair(unsigned_int::<usize>, tag(&b" "[..]), unsigned_int::<u32>),
444	        preceded(pair(opt(tag(&b" "[..])), eol), many0(xref_entry)),
445	    );
446	
447	    delimited(
448	        pair(tag(&b"xref"[..]), eol),
449	        fold_many1(
450	            xref_section,
451	            || -> Xref { Xref::new(0, XrefType::CrossReferenceTable) },
452	            |mut xref, ((start, _count), entries)| {
453	                for (index, ((offset, generation), is_normal)) in entries.into_iter().enumerate() {
454	                    if is_normal {
455	                        if let Ok(generation) = generation.try_into() {
456	                            xref.insert((start + index) as u32, XrefEntry::Normal { offset, generation });
457	                        }
458	                    }
459	                }
460	                xref
461	            },
462	        ),
463	        space,
464	    ).parse(input)
465	}
466	
467	fn trailer(input: ParserInput) -> NomResult<Dictionary> {
468	    delimited(pair(tag(&b"trailer"[..]), space), dictionary, space).parse(input)
469	}
470	
471	pub fn xref_and_trailer(input: ParserInput, reader: &Reader) -> crate::Result<(Xref, Dictionary)> {
472	    let xref_trailer = map(pair(xref, trailer), |(mut xref, trailer)| {
473	        xref.size = trailer
474	            .get(b"Size")
475	            .and_then(Object::as_i64)
476	            .map_err(|_| error::ParseError::InvalidTrailer)? as u32;
477	        Ok((xref, trailer))
478	    });
479	    alt((
480	        xref_trailer,
481	        (|input| {
482	            _indirect_object(input, 0, None, reader, &mut HashSet::new())
483	                .map(|(_, obj)| {
484	                    let res = match obj {
485	                        Object::Stream(stream) => decode_xref_stream(stream),
486	                        _ => Err(crate::error::ParseError::InvalidXref.into()),
487	                    };
488	                    (input, res)
489	                })
490	                .map_err(|_| {
491	                    // artificial error kind is created to allow descriptive nom errors
492	                    nom::Err::Error(NomError::from_error_kind(input, ErrorKind::Fail))
493	                })
494	        }),
495	    )).parse(input)
496	    .map(|(_, o)| o)
497	    .map_err(|_| error::ParseError::InvalidTrailer)?
498	}
