500	pub fn xref_start(input: ParserInput) -> Option<i64> {
501	    strip_nom(delimited(
502	        pair(tag(&b"startxref"[..]), eol),
503	        trim_spaces(integer),
504	        (eol, tag(&b"%%EOF"[..]), space),
505	    ).parse(input))
506	}
