508	fn trim_spaces<'a, O>(
509	    p: impl Parser<ParserInput<'a>, Output = O, Error = nom::error::Error<LocatedSpan<&'a [u8], &'a str>>>,
510	) -> impl Parser<ParserInput<'a>, Output = O, Error = nom::error::Error<LocatedSpan<&'a [u8], &'a str>>> {
511	    delimited(many0(tag(" ")), p, many0(tag(" ")))
512	}
