527	fn operand(input: ParserInput) -> NomResult<Object> {
528	    terminated(
529	        alt((
530	            null,
531	            boolean,
532	            map(real, Object::Real),
533	            map(integer, Object::Integer),
534	            map(name, Object::Name),
535	            map(literal_string, Object::string_literal),
536	            hexadecimal_string,
537	            map(array, Object::Array),
