544	fn operation(input: ParserInput) -> NomResult<Operation> {
545	    map(
546	        preceded(
547	            many0(comment),
548	            alt((inline_image, terminated(pair(many0(operand), operator), content_space))),
549	        ),
550	        |(operands, operator)| Operation { operator, operands },
551	    ).parse(input)
