553	
554	fn inline_image(input: ParserInput) -> NomResult<(Vec<Object>, String)> {
555	    preceded(pair(tag(&b"BI"[..]), content_space), cut(inline_image_impl)).parse(input)
556	}
557	
558	fn inline_image_impl(input: ParserInput) -> NomResult<(Vec<Object>, String)> {
559	    let (input, stream_dict) = inner_dictionary.parse(input)?;
560	    let (input, _) = pair(tag(&b"ID"[..]), content_space).parse(input)?;
561	    match image_data_stream(input, stream_dict) {
562	        Ok((input, stream)) => {
563	            let (input, _) = (content_space, tag(&b"EI"[..]), content_space).parse(input)?;
564	            Ok((input, (vec![Object::Stream(stream)], String::from("BI"))))
565	        }
566	        Err(e) => {
567	            // Skip to EI marker so the rest of the content stream can still be parsed.
568	            log::warn!("Skipping unparseable inline image: {e}");
569	            let bytes = input.fragment();
570	            // EI must appear after whitespace to distinguish from data bytes.
571	            let ei_pos = bytes.windows(4)
572	                .position(|w| (w[0] == b' ' || w[0] == b'\n' || w[0] == b'\r')
573	                    && w[1] == b'E' && w[2] == b'I'
574	                    && (w[3] == b' ' || w[3] == b'\n' || w[3] == b'\r'))
575	                .ok_or_else(|| {
576	                    let err: NomError = nom::error::Error::from_error_kind(input, ErrorKind::Fail);
577	                    nom::Err::Failure(err)
578	                })?;
579	            let (input, _) = take(ei_pos + 3).parse(input)
580	                .map_err(|_: nom::Err<()>| {
581	                    let err: NomError = nom::error::Error::from_error_kind(input, ErrorKind::Fail);
582	                    nom::Err::Failure(err)
583	                })?;
584	            let (input, _) = content_space(input)?;
585	            Ok((input, (vec![], String::from("BI"))))
586	        }
587	    }
588	}
589	
590	fn image_data_stream(input: ParserInput, stream_dict: Dictionary) -> crate::Result<(ParserInput, Stream)> {
591	    let get_abbr = |key_abbr: &[u8], key: &[u8]| stream_dict.get(key_abbr).or_else(|_| stream_dict.get(key));
592	    let width = get_abbr(b"W", b"Width")?.as_i64()? as usize;
593	    let height = get_abbr(b"H", b"Height")?.as_i64()? as usize;
594	    let bpc = get_abbr(b"BPC", b"BitsPerComponent")?.as_i64()? as usize;
595	    let im = get_abbr(b"IM", b"ImageMask").and_then(|x| x.as_bool());
596	    let num_colors = match im {
597	        // If we have an image mask then we don't have a colorspace
598	        Ok(true) => 1,
599	        _ => {
600	            let colorspace = get_abbr(b"CS", b"ColorSpace").unwrap().as_name()?;
601	            match colorspace {
602	                b"DeviceGray" | b"Gray" => 1,
603	                b"DeviceRGB" | b"RGB" => 3,
604	                b"DeviceRGBA" | b"RGBA" => 4,
605	                b"DeviceCMYK" | b"CMYK" => 4,
606	                b"Pattern" => {
607	                    log::warn!("Pattern colorspace is not allowed in inline images");
608	                    return Err(Error::InvalidInlineImage(String::from(
609	                        "Pattern colorspace is not allowed in inline images",
610	                    )));
611	                }
612	                _ => {
613	                    log::warn!("Colorspace of inline image not recognized / not yet implemented");
614	                    return Err(Error::Unimplemented("inline image colorspaces"));
615	                }
616	            }
617	        }
618	    };
619	
620	    let stride = (width * (num_colors * bpc)).div_ceil(8);
621	    let length = height * stride;
622	
623	    let (input, content) = match get_abbr(b"F", b"Filter") {
624	        Err(_) => {
625	            // no decompression needed as no filter was applied
626	            take(length).parse(input).map_err(|_: nom::Err<()>| crate::error::ParseError::EndOfInput)?
627	        }
628	        Ok(Object::Name(_filter)) => {
629	            log::warn!("Filters for inline images are not yet implemented");
630	            return Err(Error::Unimplemented("filters for inline images"));
631	        }
632	        Ok(Object::Array(_filters)) => {
633	            log::warn!("Filters for inline images are not yet implemented");
634	            return Err(Error::Unimplemented("filters for inline images"));
635	        }
636	        Ok(obj) => {
637	            log::warn!("Filter must be either a Name or and Array.");
638	            return Err(Error::ObjectType {
639	                expected: "Name or Array",
640	                found: obj.enum_variant(),
641	            });
642	        }
643	    };
644	    Ok((input, Stream::new(stream_dict, content.to_vec())))
645	}
646	
647	fn _content(input: ParserInput) -> NomResult<Content<Vec<Operation>>> {
648	    preceded(
649	        content_space,
650	        map(many0(operation), |operations| Content { operations }),
651	    ).parse(input)
652	}
653	
654	pub fn content(input: ParserInput) -> Option<Content<Vec<Operation>>> {
655	    strip_nom(_content.parse(input))
656	}
